 36→function formatTime(seconds: number): string {
 37→  const m = Math.floor(seconds / 60);
 38→  const s = seconds % 60;
 39→  return `${m}:${s.toString().padStart(2, "0")}`;
 40→}
 41→
 42→function parseStepTime(time: string): number {
 43→  const [m, s] = time.split(":").map(Number);
 44→  return m * 60 + (s ?? 0);
 45→}
 46→
 47→function getCardBorderPath(race: Race | null): string {
 48→  if (race === "Orc") return "./buttons/esc/orc/orc-options-menu-border.blp";
 49→  if (race === "NightElf")
 50→    return "./buttons/esc/nightelf/nightelf-options-menu-border.blp";
 51→  if (race === "Undead")
 52→    return "./buttons/esc/undead/undead-options-menu-border.blp";
 53→  return "./buttons/esc/human/human-options-menu-border.blp";
 54→}
 55→
 56→function useCardBorderImage(race: Race | null): string {
 57→  const [borderImageUrl, setBorderImageUrl] = useState("");
 58→
 59→  useEffect(() => {
 60→    let cancelled = false;
 61→    const path = getCardBorderPath(race);
 62→    void loadBlpDataUrl(path)
 63→      .then((url) => loadDataUrlImage(url))
 64→      .then((img) => {
 65→        if (cancelled) return;
 66→        setBorderImageUrl(composeBorderImageFromAtlas(img));
 67→      })
 68→      .catch((err) => console.error(err));
 69→    return () => {
 70→      cancelled = true;
 71→    };
 72→  }, [race]);
 73→
 74→  return borderImageUrl;
 75→}
 76→
 77→function useSupplyIcon(): string {
 78→  const [url, setUrl] = useState("");
 79→  useEffect(() => {
 80→    void loadBlpDataUrl("./resources/ResourceSupply.blp").then(setUrl);
 81→  }, []);
 82→  return url;
 83→}
