290→export default function BuildOrdersSection() {
291→  const running = useTimerRunning();
292→  const elapsed = useElapsedSeconds();
293→  const currentRace = useCurrentRace();
294→  const borderImageUrl = useCardBorderImage(currentRace);
295→  const allBuilds = useBuildOrders();
296→
297→  const relevantBuilds = allBuilds.filter(
298→    (b) => !currentRace || b.race === currentRace,
299→  );
300→
301→  const [selectedIndex, setSelectedIndex] = useState(0);
302→  const [importStatus, setImportStatus] = useState("");
303→  const fileInputRef = useRef<HTMLInputElement>(null);
304→
305→  // Reset selection and timer when race changes
306→  useEffect(() => {
307→    setSelectedIndex(0);
308→    resetTimer();
309→  }, [currentRace]);
310→
311→  const selectedBuild =
312→    relevantBuilds.length > 0
313→      ? relevantBuilds[Math.min(selectedIndex, relevantBuilds.length - 1)]
314→      : null;
315→
316→  // Build dropdown option keys — use indices as stable identifiers
317→  const optionKeys = relevantBuilds.map((_, i) => String(i));
318→
319→  const handleImport = useCallback(() => {
320→    fileInputRef.current?.click();
321→  }, []);
322→
323→  const handleExport = useCallback(() => {
324→    if (!selectedBuild) return;
325→    // Build a clean object with properties ordered to match the BuildOrder interface
326→    const clean: Record<string, unknown> = {
327→      name: selectedBuild.name,
328→      race: selectedBuild.race,
329→    };
330→    if (selectedBuild.vs) clean.vs = selectedBuild.vs;
331→    clean.description = selectedBuild.description;
332→    if (selectedBuild.difficulty) clean.difficulty = selectedBuild.difficulty;
333→    if (selectedBuild.keyTiming) clean.keyTiming = selectedBuild.keyTiming;
334→    clean.steps = selectedBuild.steps;
335→    if (selectedBuild.note) clean.note = selectedBuild.note;
336→    if (selectedBuild.skillOrder && selectedBuild.skillOrder.length > 0) {
337→      clean.skillOrder = selectedBuild.skillOrder;
338→    }
339→    const json = JSON.stringify([clean], null, 2);
340→    const blob = new Blob([json], { type: "application/json" });
341→    const url = URL.createObjectURL(blob);
342→    const a = document.createElement("a");
343→    a.href = url;
344→    a.download = `${selectedBuild.name.replace(/[^a-zA-Z0-9_-]/g, "_")}.json`;
345→    a.click();
346→    
347→    URL.revokeObjectURL(url);
348→  }, [selectedBuild]);
349→
350→  const handleFileChange = useCallback(
351→    (e: React.ChangeEvent<HTMLInputElement>) => {
352→      const file = e.target.files?.[0];
353→      if (!file) return;
354→
355→      const reader = new FileReader();
356→      reader.onload = () => {
357→        try {
358→          const json = JSON.parse(reader.result as string);
359→          const count = importBuilds(json);
360→          if (count > 0) {
361→            setImportStatus(`Imported ${count} build${count > 1 ? "s" : ""}`);
362→          } else {
363→            setImportStatus("No valid builds found in file");
364→          }
365→        } catch {
366→          setImportStatus("Invalid JSON file");
367→        }
368→        // Clear so the same file can be re-imported
369→        e.target.value = "";
370→        setTimeout(() => setImportStatus(""), 4000);
371→      };
372→      reader.readAsText(file);
373→    },
374→    [],
375→  );
376→
377→  return (
378→    <div className="tab-content">
379→      <section className="section-card build-orders-section">
380→        <div className="build-orders-toolbar">
381→          <h3>Build Orders</h3>
382→          <div className="build-orders-toolbar-actions">
383→            <div className="build-orders-race-picker">
384→              <GlueDropdown
385→                options={RACES}
386→                value={currentRace}
387→                onChange={(v) => setCurrentRace(v as Race)}
388→                label={(v) => RACE_LABELS[v as Race] ?? v}
389→              />
390→            </div>
391→            {relevantBuilds.length > 1 && (
392→              <GlueDropdown
393→                options={optionKeys}
394→                value={String(
395→                  Math.min(selectedIndex, relevantBuilds.length - 1),
396→                )}
397→                onChange={(v) => {
398→                  setSelectedIndex(Number(v));
399→                  resetTimer();
400→                }}
401→                label={(v) => relevantBuilds[Number(v)]?.name ?? ""}
402→              />
403→            )}
404→            <GlueBorderedButton onClick={handleImport}>Import</GlueBorderedButton>
405→            <GlueBorderedButton onClick={handleExport} disabled={!selectedBuild}>Export</GlueBorderedButton>
406→            <input
407→              ref={fileInputRef}
408→              type="file"
409→              accept=".json"
410→              className="build-import-input"
411→              onChange={handleFileChange}
412→            />
413→          </div>
414→        </div>
415→        {importStatus && (
416→          <div className="build-import-status">{importStatus}</div>
417→        )}
418→
419→        {!selectedBuild ? (
420→          <p className="build-card-empty">
421→            No build orders available for this race.
422→          </p>
423→        ) : (
424→          <>
425→            <BuildCard
426→              key={`${currentRace}-${selectedIndex}`}
427→              build={selectedBuild}
428→              elapsed={elapsed}
429→              running={running}
430→              borderImageUrl={borderImageUrl}
431→            />
432→            {selectedBuild.skillOrder && selectedBuild.skillOrder.length > 0 && (
433→              <SkillOrderSection skillOrder={selectedBuild.skillOrder} />
434→            )}
435→            <BuildOrderInputSection />
436→          </>
437→        )}
438→      </section>
439→      <FooterSection race={currentRace}/>
440→    </div>
441→  );
442→}
