156→async function loadImage(src: string): Promise<HTMLImageElement> {
157→  return new Promise((resolve, reject) => {
158→    const img = new Image();
159→    img.onload = () => resolve(img);
160→    img.onerror = () => reject(new Error(`Failed to load image: ${src}`));
161→    img.src = src;
162→  });
163→}
164→
165→function drawNearest(
166→  ctx: CanvasRenderingContext2D,
167→  image: HTMLImageElement,
168→  x: number,
169→  y: number,
170→  width: number,
171→  height: number,
172→) {
173→  ctx.save();
174→  ctx.imageSmoothingEnabled = false;
175→  ctx.drawImage(image, x, y, width, height);
176→  ctx.restore();
177→}
178→
179→function drawUnitQueuePreview(
180→  canvas: HTMLCanvasElement,
181→  backdropImage: HTMLImageElement,
182→  iconImage: HTMLImageElement | null,
183→) {
184→  const rect = canvas.getBoundingClientRect();
185→  const cssW = Math.max(1, rect.width);
186→  const cssH = Math.max(1, rect.height);
187→  const dpr = window.devicePixelRatio || 1;
188→  const pxW = Math.max(1, Math.round(cssW * dpr));
189→  const pxH = Math.max(1, Math.round(cssH * dpr));
190→  if (canvas.width !== pxW || canvas.height !== pxH) {
191→    canvas.width = pxW;
192→    canvas.height = pxH;
193→  }
194→
195→  const ctx = canvas.getContext('2d');
196→  if (!ctx) return;
197→
198→  const scaleX = cssW / UNIT_QUEUE_SIZE.width;
199→  const scaleY = cssH / UNIT_QUEUE_SIZE.height;
200→
201→  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
202→  ctx.clearRect(0, 0, cssW, cssH);
203→  ctx.imageSmoothingEnabled = false;
204→  ctx.drawImage(backdropImage, 0, 0, cssW, cssH);
205→  if (!iconImage) return;
206→
207→  for (const box of UNIT_QUEUE_ICON_BOXES) {
208→    drawNearest(ctx, iconImage, box.x * scaleX, box.y * scaleY, box.width * scaleX, box.height * scaleY);
209→  }
210→}
