212→export function UnitQueueSection(props: UnitQueueSectionProps) {
213→  const canvasRef = useRef<HTMLCanvasElement>(null);
214→
215→  useEffect(() => {
216→    const canvas = canvasRef.current;
217→    const backdropUrl = props.backdropUrl;
218→    const iconUrl = props.iconUrl;
219→    if (!canvas || !backdropUrl) return;
220→
221→    let cancelled = false;
222→    void Promise.all([
223→      loadImage(backdropUrl),
224→      iconUrl ? loadImage(iconUrl) : Promise.resolve(null),
225→    ])
226→      .then(([backdropImage, iconImage]) => {
227→        if (cancelled) return;
228→        drawUnitQueuePreview(canvas, backdropImage, iconImage);
229→      })
230→      .catch((error) => console.error(error));
231→
232→    return () => {
233→      cancelled = true;
234→    };
235→  }, [props.backdropUrl, props.iconUrl]);
236→
237→  return (
238→    <section className="section-card">
239→      <h3>Unit Queue</h3>
240→      <p className="section-desc">
241→        A task queue with progress indicator and cancelable pending slots. Perfect for managing build pipelines, AI agent workflows, or anything that trains in 30 seconds.
242→      </p>
243→      <div className="unit-queue-preview">
244→        <div className="unit-queue-stage" aria-label="Build queue backdrop preview">
245→          {props.backdropUrl ? (
246→            <canvas ref={canvasRef} className="unit-queue-canvas" />
247→          ) : (
248→            <div className="unit-queue-fallback" />
249→          )}
250→        </div>
251→      </div>
252→    </section>
253→  );
254→}
