 63→  const alphaAt = (x: number, y: number) => alpha[(y * width + x) * 4 + 3];
 64→  if (inBounds(startX, startY) && alphaAt(startX, startY) === 0) return startY * width + startX;
 65→  const maxRadius = Math.max(width, height);
 66→  for (let r = 1; r < maxRadius; r++) {
 67→    for (let dy = -r; dy <= r; dy++) {
 68→      const y = startY + dy;
 69→      const x1 = startX - r; const x2 = startX + r;
 70→      if (inBounds(x1, y) && alphaAt(x1, y) === 0) return y * width + x1;
 71→      if (inBounds(x2, y) && alphaAt(x2, y) === 0) return y * width + x2;
 72→    }
 73→    for (let dx = -r + 1; dx <= r - 1; dx++) {
 74→      const x = startX + dx;
