 43→async function loadBLPMips(path: string): Promise<ImageData[]> {
 44→  const cached = blpCache.get(path);
 45→  if (cached) return cached;
 46→  const res = await fetch(path);
 47→  if (!res.ok) throw new Error(`Failed to load worker unit texture: ${path}`);
 48→  const ab = await res.arrayBuffer();
 49→  const blp = decodeBLP(ab);
 50→  const mips: ImageData[] = [];
 51→  const maxLevels = Math.max(1, Math.floor(Math.log2(Math.max(blp.width, blp.height))) + 1);
 52→  for (let i = 0; i < maxLevels; i++) {
 53→    const w = blp.width >> i; const h = blp.height >> i;
 54→    if (w <= 0 || h <= 0) break;
 55→    try {
 56→      const img = getBLPImageData(blp, i);
 57→      if (!img || !img.width || !img.height) break;
 58→      mips.push(new ImageData(new Uint8ClampedArray(img.data), img.width, img.height));
 59→      if (img.width === 1 && img.height === 1) break;
 60→    } catch { break; }
 61→  }
 62→  if (mips.length === 0) throw new Error(`No mip levels decoded for worker unit texture: ${path}`);
 63→  blpCache.set(path, mips);
 64→  return mips;
 65→}
