 75→    Undead: ['stand work', 'stand 2', 'stand - 2', 'stand ready', 'stand'],
 76→  };
 77→  for (const pref of preferencesByRace[race]) {
 78→    const idx = sequenceNames.findIndex((name) => name.includes(pref));
