import { defineConfig } from "vite";
import react from "@vitejs/plugin-react";

export default defineConfig({
  plugins: [react()],
  base: '/wc3-build-order-app/',
  server: {
    port: 3000,
  },
  build: {
    target: "esnext",
  },
});

return (
  <div className="build-card">
    {/* Left column */}
    <div className="build-card-info">
      <div className="build-card-header">
        {buildRace && (
          <div className="build-card-portrait">
            <div
              className="build-card-portrait-window"
              style={{
                "--portrait-window-mask": `url("./console/${buildRace}/${RACE_PREFIXES[buildRace].tile}UIPortraitWindowMask.png")`,
              } as React.CSSProperties}
            >
              <HeroPortraitModel race={buildRace} />
            </div>
            <img
              src={`./console/${buildRace}/${RACE_PREFIXES[buildRace].tile}UIPortraitFrameCrop.png`}
              alt=""
              className="build-card-portrait-frame"
            />
          </div>
        )}
        <div className="build-card-header-text">
          <h4 className="build-card-title">{build.name}</h4>
          <div className="build-card-subtitle">
            {build.vs && (
              <span className="build-card-matchup">vs {build.vs}</span>
            )}
