    parseNumber(state); // count, not used

    strictParseSymbol(state, '{');

    const lineType: string = parseKeyword(state);
    if (lineType === 'DontInterp' || lineType === 'Linear' || lineType === 'Hermite' || lineType === 'Bezier') {
