import { useEffect, useRef } from 'react';
import { ModelRenderer, decodeBLP, getBLPImageData, parseMDX } from 'war3-model';
import { mat3, mat4, quat, vec3 } from 'gl-matrix';
import type { Race } from '../lib/types';

type ModelType = ReturnType<typeof parseMDX>;
type WorkerSide = 'left' | 'right';

interface WorkerUnitConfig {
  modelPath: string;
  textures: Record<string, string>;
}

const WORKER_UNIT_CONFIG: Record<Race, WorkerUnitConfig> = {
  Human: { modelPath: './models/worker-units/Human/peasant.mdx', textures: { 'textures/peasant.blp': './models/worker-units/textures/Peasant.blp', 'textures/gutz.blp': './models/worker-units/textures/gutz.blp' } },
  Orc: { modelPath: './models/worker-units/Orc/peon.mdx', textures: { 'units/orc/peon/peon.blp': './models/worker-units/Orc/peon.blp', 'textures/gutz.blp': './models/worker-units/textures/gutz.blp' } },
  NightElf: { modelPath: './models/worker-units/NightElf/Archer.mdx', textures: { 'textures/ranger.blp': './models/worker-units/textures/Ranger.blp', 'textures/star2_32.blp': './models/worker-units/textures/star2_32.blp', 'textures/gutz.blp': './models/worker-units/textures/gutz.blp' } },
  Undead: { modelPath: './models/worker-units/Undead/Acolyte.mdx', textures: { 'textures/acolyte.blp': './models/worker-units/textures/Acolyte.blp', 'textures/green_star.blp': './models/worker-units/textures/Green_Star.blp', 'textures/demonrune3.blp': './models/worker-units/textures/DemonRune3.blp', 'textures/gutz.blp': './models/worker-units/textures/gutz.blp' } },
};

const modelCache = new Map<string, ModelType>();
const blpCache = new Map<string, ImageData[]>();

function normalizeTexturePath(textureImage: string): string { return textureImage.replaceAll('\\', '/').toLowerCase(); }

function getTexturePath(textureImage: string, race: Race): string | null {
  const normalized = normalizeTexturePath(textureImage);
  if (!normalized) return null;
  return WORKER_UNIT_CONFIG[race].textures[normalized] || null;
}

