420→async function loadBlpDataUrl(path: string): Promise<string> {
421→  const cached = iconDataUrlCache.get(path);
422→  if (cached) return cached;
423→
424→  const promise = (async () => {
425→    const res = await fetch(path);
426→    if (!res.ok) throw new Error(`Failed to fetch icon ${path}`);
427→    const ab = await res.arrayBuffer();
428→    const blp = decodeBLP(ab);
429→    const img = getBLPImageData(blp, 0);
430→    const pixelData = new Uint8ClampedArray(img.data);
431→    if (shouldForceOpaqueOnZeroAlpha(path)) {
432→      let allAlphaZero = true;
433→      for (let i = 3; i < pixelData.length; i += 4) {
434→        if (pixelData[i] !== 0) {
435→          allAlphaZero = false;
436→          break;
437→        }
438→      }
439→      if (allAlphaZero) {
440→        for (let i = 3; i < pixelData.length; i += 4) {
441→          pixelData[i] = 255;
442→        }
443→      }
444→    }
445→    if (shouldApplyBlackColorKey(path)) {
446→      for (let i = 0; i < pixelData.length; i += 4) {
447→        const r = pixelData[i];
448→        const g = pixelData[i + 1];
449→        const b = pixelData[i + 2];
450→        const a = pixelData[i + 3];
451→        if (a > 224 && r <= 10 && g <= 10 && b <= 10) {
452→          pixelData[i + 3] = 0;
453→        }
454→      }
455→    }
456→    const canvas = document.createElement("canvas");
457→    canvas.width = img.width;
458→    canvas.height = img.height;
459→    const ctx = canvas.getContext("2d");
460→    if (!ctx) throw new Error(`Failed to decode icon ${path}`);
461→    ctx.putImageData(new ImageData(pixelData, img.width, img.height), 0, 0);
462→    return canvas.toDataURL("image/png");
463→  })();
464→
465→  iconDataUrlCache.set(path, promise);
466→  return promise;
467→}
