588→function rotateCellClockwise(
589→  atlas: HTMLImageElement,
590→  cellIndex: number,
591→  cellW: number,
592→  cellH: number,
593→): HTMLCanvasElement {
594→  const canvas = document.createElement("canvas");
595→  canvas.width = cellH;
596→  canvas.height = cellW;
597→  const ctx = canvas.getContext("2d");
598→  if (!ctx) return canvas;
599→  ctx.translate(cellH, 0);

600→  ctx.rotate(Math.PI / 2);
601→  ctx.drawImage(atlas, cellIndex * cellW, 0, cellW, cellH, 0, 0, cellW, cellH);
602→  return canvas;
603→}
604→
605→function drawGlueNineSliceToCanvas(
606→  canvas: HTMLCanvasElement,
607→  bgImg: HTMLImageElement,
608→  borderImg: HTMLImageElement,
609→  hoverImg: HTMLImageElement | null,
610→  hovered: boolean,
611→) {
612→  const cssW = Math.max(1, canvas.clientWidth || 1);
613→  const cssH = Math.max(1, canvas.clientHeight || 1);
614→  const dpr = window.devicePixelRatio || 1;
615→  const pxW = Math.max(1, Math.round(cssW * dpr));
616→  const pxH = Math.max(1, Math.round(cssH * dpr));
617→  if (canvas.width !== pxW || canvas.height !== pxH) {
618→    canvas.width = pxW;
619→    canvas.height = pxH;
620→  }
621→
622→  const ctx = canvas.getContext("2d");
623→  if (!ctx) return;
624→  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
625→  ctx.clearRect(0, 0, cssW, cssH);
626→
627→  const atlasW = borderImg.width;
628→  const atlasH = borderImg.height;
629→  const cellW = atlasW / 8;
630→  const corner = Math.max(
631→    1,
632→    Math.floor(Math.min(cellW, cssH * 0.35, cssW / 2, cssH / 2)),
633→  );
634→  const inset = Math.max(1, Math.round(corner * 0.25));
635→
636→  // Fill inner area with opaque black before pattern to handle textures with alpha
637→  // (NightElf/Undead bg textures use DXT3/5 with alpha; game renders on opaque framebuffer)
638→  ctx.fillStyle = "#000";
639→  ctx.fillRect(inset, inset, cssW - inset * 2, cssH - inset * 2);
640→
641→  const pattern = ctx.createPattern(bgImg, "repeat");
642→  if (pattern) {
643→    ctx.fillStyle = pattern;
644→    ctx.fillRect(inset, inset, cssW - inset * 2, cssH - inset * 2);
645→  }
646→
647→  const drawCell = (
648→    idx: number,
649→    x: number,
650→    y: number,
651→    w: number,
652→    h: number,
653→  ) => {
654→    ctx.drawImage(borderImg, idx * cellW, 0, cellW, atlasH, x, y, w, h);
655→  };
656→
657→  drawCell(4, 0, 0, corner, corner);
658→  drawCell(5, cssW - corner, 0, corner, corner);
659→  drawCell(6, 0, cssH - corner, corner, corner);
660→  drawCell(7, cssW - corner, cssH - corner, corner, corner);
661→
662→  const edgeH = cssH - corner * 2;
663→  if (edgeH > 0) {
664→    drawCell(0, 0, corner, corner, edgeH);
665→    drawCell(1, cssW - corner, corner, corner, edgeH);
666→  }
667→
668→  const edgeW = cssW - corner * 2;
669→  if (edgeW > 0) {
670→    const topRot = rotateCellClockwise(borderImg, 2, cellW, atlasH);
671→    const bottomRot = rotateCellClockwise(borderImg, 3, cellW, atlasH);
672→    ctx.drawImage(topRot, corner, 0, edgeW, corner);
673→    ctx.drawImage(bottomRot, corner, cssH - corner, edgeW, corner);
674→  }
675→
676→  if (hovered && hoverImg) {
677→    const temp = document.createElement("canvas");
678→    temp.width = pxW;
679→    temp.height = pxH;
680→    const tCtx = temp.getContext("2d");
681→    if (tCtx) {
682→      tCtx.setTransform(dpr, 0, 0, dpr, 0, 0);
683→      tCtx.drawImage(canvas, 0, 0, cssW, cssH);
684→      tCtx.globalCompositeOperation = "source-in";
685→      tCtx.drawImage(hoverImg, 0, 0, cssW, cssH);
686→      ctx.save();
687→      ctx.globalCompositeOperation = "lighter";
688→      ctx.drawImage(temp, 0, 0, cssW, cssH);
689→      ctx.restore();
690→    }
691→  }
692→}
