694→interface NineSliceTemplateOptions {
695→  cornerPx: number;
696→  insetPx: number;
697→  tileBackground?: boolean;
698→  tileHorizontalEdges?: boolean;
699→  opaqueBaseFill?: string | null;
700→  fillCornerMaxPx?: number;
701→}
702→
703→function drawHorizontallyTiledEdge(
704→  ctx: CanvasRenderingContext2D,
705→  tile: HTMLCanvasElement,
706→  x: number,
707→  y: number,
708→  width: number,
709→  height: number,
710→) {
711→  if (width <= 0 || height <= 0) return;
712→
713→  let drawn = 0;
714→  while (drawn < width) {
715→    const segmentW = Math.min(height, width - drawn);
716→    const srcW = (segmentW / height) * tile.width;
717→    ctx.drawImage(
718→      tile,
719→      0,
720→      0,
721→      srcW,
722→      tile.height,
723→      x + drawn,
724→      y,
725→      segmentW,
726→      height,
727→    );
728→    drawn += segmentW;
729→  }
730→}
731→
732→function drawTemplateNineSliceToCanvas(
733→  canvas: HTMLCanvasElement,
734→  bgImg: HTMLImageElement,
735→  borderImg: HTMLImageElement,
736→  options: NineSliceTemplateOptions,
737→) {
738→  const cssW = Math.max(1, canvas.clientWidth || 1);
739→  const cssH = Math.max(1, canvas.clientHeight || 1);
740→  const dpr = window.devicePixelRatio || 1;
741→  const pxW = Math.max(1, Math.round(cssW * dpr));
742→  const pxH = Math.max(1, Math.round(cssH * dpr));
743→  if (canvas.width !== pxW || canvas.height !== pxH) {
744→    canvas.width = pxW;
745→    canvas.height = pxH;
746→  }
747→
748→  const ctx = canvas.getContext("2d");
749→  if (!ctx) return;
750→  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
751→  ctx.clearRect(0, 0, cssW, cssH);
752→
753→  const atlasW = borderImg.width;
754→  const atlasH = borderImg.height;
755→  const cellW = atlasW / 8;
756→  const sourceCornerMax = Math.max(1, Math.floor(Math.min(cellW, atlasH)));
757→  const corner = Math.max(
758→    1,
759→    Math.floor(Math.min(options.cornerPx, sourceCornerMax, cssW / 2, cssH / 2)),
760→  );
761→  const inset = Math.max(
762→    0,
763→    Math.floor(Math.min(options.insetPx, cssW / 2, cssH / 2)),
764→  );
765→  const innerX = inset;
766→  const innerY = inset;
767→  const innerW = Math.max(0, cssW - inset * 2);
768→  const innerH = Math.max(0, cssH - inset * 2);
769→  // Large controls (textarea/listbox) reuse the same nine-slice templates; cap fill corner
770→  // radius to prevent over-rounded clipping that exposes page background.
771→  const fillCornerCapPx = options.fillCornerMaxPx ?? 8;
772→  const fillCorner = Math.max(
773→    0,
774→    Math.floor(Math.min(corner, fillCornerCapPx, innerW / 2, innerH / 2)),
775→  );
776→
777→  if (innerW > 0 && innerH > 0) {
778→    ctx.save();
779→    ctx.beginPath();
780→    if (fillCorner > 0) {
781→      ctx.roundRect(innerX, innerY, innerW, innerH, fillCorner);
782→    } else {
783→      ctx.rect(innerX, innerY, innerW, innerH);
784→    }
785→    ctx.clip();
786→
787→    if (options.opaqueBaseFill) {
788→      ctx.fillStyle = options.opaqueBaseFill;
789→      ctx.fillRect(innerX, innerY, innerW, innerH);
790→    }
791→    if (options.tileBackground === false) {
792→      ctx.drawImage(
793→        bgImg,
794→        0,
795→        0,
796→        bgImg.width,
797→        bgImg.height,
798→        innerX,
799→        innerY,

800→        innerW,
801→        innerH,
802→      );
803→    } else {
804→      const pattern = ctx.createPattern(bgImg, "repeat");
805→      if (pattern) {
806→        ctx.fillStyle = pattern;
807→        ctx.fillRect(innerX, innerY, innerW, innerH);
808→      }
809→    }
810→    ctx.restore();
811→  }
812→
813→  const drawCell = (
814→    idx: number,
815→    x: number,
816→    y: number,
817→    w: number,
818→    h: number,
819→  ) => {
820→    ctx.drawImage(borderImg, idx * cellW, 0, cellW, atlasH, x, y, w, h);
821→  };
822→
823→  drawCell(4, 0, 0, corner, corner);
824→  drawCell(5, cssW - corner, 0, corner, corner);
825→  drawCell(6, 0, cssH - corner, corner, corner);
826→  drawCell(7, cssW - corner, cssH - corner, corner, corner);
827→
828→  const edgeH = cssH - corner * 2;
829→  if (edgeH > 0) {
830→    drawCell(0, 0, corner, corner, edgeH);
831→    drawCell(1, cssW - corner, corner, corner, edgeH);
832→  }
833→
834→  const edgeW = cssW - corner * 2;
835→  if (edgeW > 0) {
836→    const topRot = rotateCellClockwise(borderImg, 2, cellW, atlasH);
837→    const bottomRot = rotateCellClockwise(borderImg, 3, cellW, atlasH);
838→    if (options.tileHorizontalEdges) {
839→      drawHorizontallyTiledEdge(ctx, topRot, corner, 0, edgeW, corner);
840→      drawHorizontallyTiledEdge(
841→        ctx,
842→        bottomRot,
843→        corner,
844→        cssH - corner,
845→        edgeW,
846→        corner,
847→      );
848→    } else {
849→      ctx.drawImage(topRot, corner, 0, edgeW, corner);
850→      ctx.drawImage(bottomRot, corner, cssH - corner, edgeW, corner);
851→    }
852→  }
853→}
