886→function modelBarFillRatio(
887→  valuePct: number,
888→  profile: StatusBarFillProfile,
889→): number {
890→  const pct = Math.max(0, Math.min(100, valuePct));
891→  const scaleX =
892→    profile.minScaleX + ((profile.maxScaleX - profile.minScaleX) * pct) / 100;
893→  return Math.max(0, Math.min(1, profile.fillToFrameWidth * scaleX));
894→}
895→
896→const additiveSrcColorScratchCanvas = document.createElement("canvas");
897→
898→function compositeSrcColorAdditive(
899→  dstCtx: CanvasRenderingContext2D,
900→  pxW: number,
901→  pxH: number,
902→  dpr: number,
903→  cssW: number,
904→  cssH: number,
905→  drawSource: (ctx: CanvasRenderingContext2D) => void,
906→) {
907→  if (
908→    additiveSrcColorScratchCanvas.width !== pxW ||
909→    additiveSrcColorScratchCanvas.height !== pxH
910→  ) {
911→    additiveSrcColorScratchCanvas.width = pxW;
912→    additiveSrcColorScratchCanvas.height = pxH;
913→  }
914→
915→  const srcCtx = additiveSrcColorScratchCanvas.getContext("2d");
916→  if (!srcCtx) return;
917→  srcCtx.setTransform(dpr, 0, 0, dpr, 0, 0);
918→  srcCtx.clearRect(0, 0, cssW, cssH);
919→  srcCtx.imageSmoothingEnabled = true;
920→  drawSource(srcCtx);
921→
922→  const srcImage = srcCtx.getImageData(0, 0, pxW, pxH);
923→  const dstImage = dstCtx.getImageData(0, 0, pxW, pxH);
924→  const src = srcImage.data;
925→  const dst = dstImage.data;
926→
927→  // Warcraft III Additive layer mode maps to GL blendFunc(SRC_COLOR, ONE).
928→  for (let i = 0; i < dst.length; i += 4) {
929→    const srcR = src[i] / 255;
930→    const srcG = src[i + 1] / 255;
931→    const srcB = src[i + 2] / 255;
932→    const srcA = src[i + 3] / 255;
933→    dst[i] = Math.min(255, dst[i] + Math.round(srcR * srcR * 255));
934→    dst[i + 1] = Math.min(255, dst[i + 1] + Math.round(srcG * srcG * 255));
935→    dst[i + 2] = Math.min(255, dst[i + 2] + Math.round(srcB * srcB * 255));
936→    dst[i + 3] = Math.min(255, dst[i + 3] + Math.round(srcA * srcA * 255));
937→  }
938→
939→  dstCtx.putImageData(dstImage, 0, 0);
940→}
941→
942→function drawSimpleStatusBarToCanvas(
943→  canvas: HTMLCanvasElement,
944→  fillImg: HTMLImageElement,
945→  borderImg: HTMLImageElement,
946→  highlightImg: HTMLImageElement | null,
947→  valuePct: number,
948→  fillProfile: StatusBarFillProfile,
949→  fillTint?: string,
950→) {
951→  const rect = canvas.getBoundingClientRect();
952→  const cssW = Math.max(1, rect.width);
953→  const cssH = Math.max(1, rect.height);
954→  const dpr = window.devicePixelRatio || 1;
955→  const pxW = Math.max(1, Math.round(cssW * dpr));
956→  const pxH = Math.max(1, Math.round(cssH * dpr));
957→  if (canvas.width !== pxW || canvas.height !== pxH) {
958→    canvas.width = pxW;
959→    canvas.height = pxH;
960→  }
961→
962→  const ctx = canvas.getContext("2d");
963→  if (!ctx) return;
964→  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
965→  ctx.clearRect(0, 0, cssW, cssH);
966→  ctx.imageSmoothingEnabled = true;
967→
968→  const fillW = cssW * modelBarFillRatio(valuePct, fillProfile);
969→  if (fillW > 0) {
970→    ctx.drawImage(
971→      fillImg,
972→      0,
973→      0,
974→      fillImg.width,
975→      fillImg.height,
976→      0,
977→      0,
978→      fillW,
979→      cssH,
980→    );
981→    if (fillTint) {
982→      ctx.save();
983→      ctx.globalCompositeOperation = "multiply";
984→      ctx.fillStyle = fillTint;
985→      ctx.fillRect(0, 0, fillW, cssH);
986→      ctx.restore();
987→    }
988→  }
989→
