1086→  const cycleMs = progressAnimCycleMs;
1087→  const wrappedMs = ((ms % cycleMs) + cycleMs) % cycleMs;
1088→  const finalMs = cycleMs - loadingSmoothToStutterMs - loadingStutterDurationMs;
1089→
1090→  if (wrappedMs < loadingSmoothToStutterMs) {
1091→    const t = wrappedMs / loadingSmoothToStutterMs;
1092→    return easeOutCubic(t) * loadingStutterStartPct;
1093→  }
1094→
1095→  if (wrappedMs < loadingSmoothToStutterMs + loadingStutterDurationMs) {
1096→    return loadingStutterPct(wrappedMs - loadingSmoothToStutterMs);
1097→  }
1098→
1099→  const finalT =
1100→    (wrappedMs - loadingSmoothToStutterMs - loadingStutterDurationMs) /
1101→    Math.max(1, finalMs);
1102→  return (
1103→    loadingStutterEndPct + easeOutCubic(finalT) * (100 - loadingStutterEndPct)
1104→  );

